PlayerListener = {}

function PlayerListener:init()
    BaseListener.registerCallBack(PlayerLoginEvent, self.onPlayerLogin)
    BaseListener.registerCallBack(PlayerLogoutEvent, self.onPlayerLogout)
    BaseListener.registerCallBack(PlayerReadyEvent, self.onPlayerReady)
    BaseListener.registerCallBack(PlayerAttackedEvent, self.onPlayerHurt)

    PlayerMoveEvent.registerCallBack(self.onPlayerMove)
    BlockBreakEvent.registerCallBack(self.onBlockBreak)
    PlayerPlaceBlockEvent.registerCallBack(self.onBlockPlace)
    PlayerAttackActorNpcEvent.registerCallBack(self.onPlayerAttackActorNpc)

    ReceiveSumRechargeEvent:registerCallBack(self.onReceiveSumRecharge)
    ReceiveSumRechargeEndEvent:registerCallBack(self.onReceiveSumRechargeEnd)
end

function PlayerListener.onPlayerLogin(clientPeer)
    local player = GamePlayer.new(clientPeer)
    player:init()
    HostApi.sendGameStatus(player.rakssid, 1)
    GamePacketSender:sendExchangeRate(player)
    return GameOverCode.Success, player
end

function PlayerListener.onPlayerLogout(player)
    AreaManager:onPlayerMove(player, 0, 99999, 0)
end

function PlayerListener.onPlayerReady(player)
    DbUtil:getPlayerData(player)
    player:changeSpeed(GameConfig.AddSpeed)
    HostApi.sendSetMoveState(player.rakssid, 2)
    AreaManager:addPlayerToTeamArea(player)
    GamePacketSender:sendRankKey(player, RankConfig.RankWeekKey)
    if player.hasReport == false then
        GameAnalytics:design(player.userId, 1, { "Player_Lv", player.level })
        player.hasReport = true
    end
    return 43200
end

function PlayerListener.onBlockBreak()
    return false
end

function PlayerListener.onBlockPlace()
    return false
end

function PlayerListener.onPlayerMove(movePlayer, x, y, z)
    if x == 0 and y == 0 and z == 0 then
        return true
    end
    local player = PlayerManager:getPlayerByPlayerMP(movePlayer)
    if player == nil then
        return true
    end

    AreaManager:onPlayerMove(player, x, y, z)

    local hash = VectorUtil.hashVector3(VectorUtil.newVector3(x, y, z))
    if hash ~= player.lastMoveHash then
        player.lastMoveTime = os.time()
    end
    player.lastMoveHash = hash
    return true
end

function PlayerListener.onPlayerAttackActorNpc(rakssid, entityId)
    local player = PlayerManager:getPlayerByRakssid(rakssid)
    if player == nil then
        return
    end
    AreaManager:actorClicked(entityId, player)
end

function PlayerListener.onPlayerHurt(hurtPlayer, hurtFrom, damageType, hurtValue)
    return false
end

function PlayerListener.onReceiveSumRecharge(player, type, id, count, meta)
    local reward = {
        RewardId = tonumber(id) or 0,
        RewardType = tonumber(type) or 0,
        RedressRewardId = 0,
        Count = tonumber(count) or 0,
        Time = 0,
        IsNotification = false,
        NotificationContent = ""
    }

    GameReward:onPlayerGetReward(player, reward)

    if tonumber(type) == Define.RewardType.Tower and player.payItemList[tostring(Define.PayStoreItem.ShortcutBarOne)] then
        if player.shortCutBar == nil then
            player.shortCutBar = {}
        end
        player.shortCutBar[tostring(2001)] = tonumber(id)
        player:addNewTowerBook(tonumber(id))
        GamePacketSender:sendTowerDefenseGetNewTower(player.rakssid, player.towerList[tonumber(id)])
    end
end

function PlayerListener.onReceiveSumRechargeEnd(player, id)
    ReportUtil.reportFirstRecharge(player, id)
end
